order by parent_id, order_num

		select distinct m.menu_id, m.parent_id, m.menu_name, m.path, m.component, m.`query`, m.route_name, m.visible, m.status, ifnull(m.perms,'') as perms, m.is_frame, m.is_cache, m.menu_type, m.icon, m.external_link, m.show_badge, m.show_text_badge, m.is_hide_tab, m.fixed_tab, m.active_path, m.is_full_page, m.new_tab, m.order_num, m.create_time
		from sys_menu m
		left join sys_role_menu rm on m.menu_id = rm.menu_id
		left join sys_user_role ur on rm.role_id = ur.role_id
		left join sys_role ro on ur.role_id = ro.role_id
		where ur.user_id = #{params.userId}
		
            AND m.menu_name like concat('%', #{menuName}, '%')
		
		
