update sys_menu
menu_name = #{menuName}, parent_id = #{parentId}, order_num = #{orderNum}, path = #{path}, component = #{component}, `query` = #{query}, route_name = #{routeName}, is_frame = #{isFrame}, is_cache = #{isCache}, menu_type = #{menuType}, visible = #{visible}, status = #{status}, perms = #{perms}, icon = #{icon}, external_link = #{externalLink}, show_badge = #{showBadge}, show_text_badge = #{showTextBadge}, is_hide_tab = #{isHideTab}, fixed_tab = #{fixedTab}, active_path = #{activePath}, is_full_page = #{isFullPage}, new_tab = #{newTab}, remark = #{remark}, update_by = #{updateBy}, update_time = sysdate()
where menu_id = #{menuId}
